srcDoc.css:
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background: transparent;
  overflow: hidden;
  font-family: Inter, system-ui, sans-serif;
}

#nav {
  display: flex;
  align-items: center;
  height: 56px;
  gap: 2px;
  padding: 0 8px;
  width: 100%;
}

.btn {
  background: transparent;
  border: none;
  color: rgba(255, 255, 255, 0.55);
  font-size: 13px;
  font-family: Inter, system-ui, sans-serif;
  font-weight: 400;
  padding: 6px 12px;
  border-radius: 5px;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
  white-space: nowrap;
}

.btn:hover {
  background: rgba(255, 255, 255, 0.08);
  color: #ffffff;
}

.btn.active {
  background: rgba(255, 255, 255, 0.15);
  color: #ffffff;
  font-weight: 600;
}

.spacer {
  flex: 1;
}

.user {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.avatar {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  background: #1A5C3A;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
  font-weight: 700;
  color: #ffffff;
}

#username {
  color: rgba(255, 255, 255, 0.65);
  font-size: 13px;
  white-space: nowrap;
}

srcDoc.js:
appsmith.onReady(function () {
  init();
});
appsmith.onModelChange(function () {
  init();
});
function init() {
  var model = appsmith.model;
  var activePage = model && model.activePage ? model.activePage : '';
  document.querySelectorAll('.btn').forEach(function (btn) {
    if (btn.getAttribute('data-page') === activePage) {
      btn.classList.add('active');
    } else {
      btn.classList.remove('active');
    }
  });
  var userName = model && model.userName ? model.userName : '';
  if (userName) {
    document.getElementById('username').textContent = userName;
    var parts = userName.trim().split(' ');
    var initials = parts.length >= 2 ? parts[0][0].toUpperCase() + parts[parts.length - 1][0].toUpperCase() : parts[0].substring(0, 2).toUpperCase();
    document.getElementById('initials').textContent = initials;
  }
}
window.go = function (eventName) {
  alert(eventName);
  appsmith.triggerEvent(eventName);
};

